用 cnt 记录连续达标天数。达标则 cnt++，根据 cnt 所在区间（1~2→1, 3~4→2, ≥5→3）决定当日红包数累加；不达标则 cnt=0。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, x, ans = 0, cnt = 0;
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> x;
        if (x >= 8000) {
            cnt++;
            if (cnt <= 2) ans += 1;
            else if (cnt <= 4) ans += 2;
            else ans += 3;
        } else cnt = 0;
    }
    cout << ans << endl;
    return 0;
}
```

枚举 i<j 无序对，同时满足类别不同且价格和为 20 才计数。i<j 保证不重复、不重复选同一件；同类过滤用 c[i]!=c[j]。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, a[1005], c[1005], ans = 0;
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    for (int i = 0; i < n; i++) cin >> c[i];
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
            if (c[i] != c[j] && a[i] + a[j] == 20) ans++;
    cout << ans << endl;
    return 0;
}
```

先算派生量 s=c+m+e、p=s-old，并标记 pend=(任一科<60?1:0)。cmp 第一关键字 pend 升序（待定靠后），再 s 降序、p 降序、id 升序。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Stu { int id, s, p, pend; } a[1005];
bool cmp(Stu x, Stu y) {
    if (x.pend != y.pend) return x.pend < y.pend;
    if (x.s != y.s) return x.s > y.s;
    if (x.p != y.p) return x.p > y.p;
    return x.id < y.id;
}
int main() {
    int n, id, old, c, m, e;
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> id >> old >> c >> m >> e;
        a[i].id = id; a[i].s = c + m + e; a[i].p = a[i].s - old;
        a[i].pend = (c < 60 || m < 60 || e < 60) ? 1 : 0;
    }
    sort(a, a + n, cmp);
    for (int i = 0; i < n; i++) cout << a[i].id << endl;
    return 0;
}
```

枚举 3×3 子矩阵左上角 (i,j)，i 从 0 到 n-3，j 从 0 到 m-3，计算 9 个数之和取最大值。ans 初始化为一个很小的数（如 -1e9）。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, a[55][55], ans = -1e9;
    cin >> n >> m;
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++) cin >> a[i][j];
    for (int i = 0; i < n - 2; i++)
        for (int j = 0; j < m - 2; j++) {
            int sum = 0;
            for (int x = 0; x < 3; x++)
                for (int y = 0; y < 3; y++) sum += a[i + x][j + y];
            ans = max(ans, sum);
        }
    cout << ans << endl;
    return 0;
}
```
